mapper.select:
SELECT * FROM check_in
WHERE user_id = #{userId}
  AND check_date = #{checkDate}
  AND deleted = 0
ORDER BY create_time DESC

SELECT COUNT(DISTINCT check_date)
FROM check_in
WHERE user_id = #{userId}
  AND check_type = #{checkType}
  AND deleted = 0
  AND check_date <= CURDATE()
  AND check_date >= (
      SELECT check_date FROM check_in
      WHERE user_id = #{userId}
        AND check_type = #{checkType}
        AND deleted = 0
      ORDER BY check_date DESC
      LIMIT 1
  )
